document.addEventListener("DOMContentLoaded",()=>{let d="/admin/colors",s=document.getElementById("color-form"),i=document.getElementById("color-name"),c=document.getElementById("color-hex"),l=document.getElementById("preview-swatch"),a=document.getElementById("color-list"),m=document.getElementById("form-submit"),u=document.getElementById("hex-error"),h=null,o=async()=>{var e=await fetch(d);if(e.ok)return e.json();throw new Error("Failed to load colors")},v=async()=>{var e=await o();a.innerHTML="",e.forEach(e=>{var t=document.createElement("div");t.className="color-item",t.innerHTML=`
        <div class="color-swatch" style="background:${e.hex_code||e.hex}"></div>
        <span>${e.name} (${e.hex_code||e.hex})</span>
        <div class="color-actions">
          <button class="edit-btn" data-id="${e.id}">✏️</button>
          <button class="del-btn" data-id="${e.id}">🗑️</button>
        </div>
      `,a.appendChild(t)})};c.addEventListener("input",()=>{var e=c.value.trim();/^#([A-Fa-f0-9]{6})$/.test(e)?(l.style.background=e,u.textContent=""):l.style.background="transparent"}),s.addEventListener("submit",async e=>{e.preventDefault();var e=i.value.trim(),t=c.value.trim().toUpperCase();if(/^#([A-Fa-f0-9]{6})$/.test(t))try{var a=h?"PUT":"POST",n=h?d+"/"+h:d,o=await fetch(n,{method:a,headers:{"Content-Type":"application/json"},body:JSON.stringify({name:e,hex:t})}),r=await o.json();if(!o.ok)throw new Error(r.message||"Error");s.reset(),h=null,m.textContent="Add Color",l.style.background="transparent",u.textContent="",await v()}catch(e){alert(e.message)}else u.textContent="Invalid hex format (e.g. #FF5733)"}),a.addEventListener("click",async e=>{e=e.target;if(e.classList.contains("edit-btn")){let t=e.dataset.id;var a=(await o()).find(e=>e.id==t);a&&(i.value=a.name,c.value=a.hex_code||a.hex,l.style.background=a.hex_code||a.hex,h=t,m.textContent="Update Color")}if(e.classList.contains("del-btn")){a=e.dataset.id;if(confirm("Delete this color?"))try{var t=await fetch(d+"/"+a,{method:"DELETE"}),n=await t.json();if(!t.ok)throw new Error(n.message||"Error");await v()}catch(e){alert(e.message)}}}),v()});